#nullable enable // autogenerated

using System;
using System.Linq;
using MVZ2Logic.Games;
using PVZEngine;

namespace MVZ2Logic.Options
{
    public static class LogicOptionExt
    {
        #region 刀喇
        public static string GetLanguage(this IGlobalOptions options) => options.GetOptionString(LogicOptionItemID.language);
        public static void SetLanguage(this IGlobalOptions options, string language) => options.SetOptionString(LogicOptionItemID.language, language);
        public static bool IsLanguageInitialized(this IGlobalOptions options) => options.TryGetOptionString(LogicOptionItemID.language, out var lang) && !string.IsNullOrEmpty(lang);
        #endregion

        #region 켜똑
        public static NamespaceID GetDifficulty(this IGlobalOptions options) => options.GetOptionID(LogicOptionItemID.difficulty) ?? GetDefaultDifficulty();
        public static void SetDifficulty(this IGlobalOptions options, NamespaceID difficulty) => options.SetOptionID(LogicOptionItemID.difficulty, difficulty);
        public static void CycleDifficulty(this IGlobalOptions options)
        {
            var difficulties = Global.Game.GetAllDifficultyDefinitions().Select(d => d.GetID()).ToArray();
            var index = Array.IndexOf(difficulties, options.GetDifficulty());
            index++;
            index %= difficulties.Length;
            options.SetDifficulty(difficulties[index]);
        }
        private static NamespaceID GetDefaultDifficulty()
        {
            return new NamespaceID(Global.BuiltinNamespace, "normal");
        }
        #endregion

        #region 슥뻣뇰랙
        public static bool IsTriggerSwapped(this IGlobalOptions options) => options.GetOptionBool(LogicOptionItemID.swapTrigger);
        public static void SetSwapTrigger(this IGlobalOptions options, bool value) => options.SetOptionBool(LogicOptionItemID.swapTrigger, value);
        #endregion

        #region 홍팁
        public static bool IsFullscreen(this IGlobalOptions options) => options.GetOptionBool(LogicOptionItemID.fullscreen);
        public static void SetFullscreen(this IGlobalOptions options, bool value) => options.SetOptionBool(LogicOptionItemID.fullscreen, value);
        #endregion

        #region HDR
        public static bool HDRLightingDisabled(this IGlobalOptions options) => !options.GetOptionBool(LogicOptionItemID.hdrLighting);
        public static void SetHDRLightingDisabled(this IGlobalOptions options, bool value) => options.SetOptionBool(LogicOptionItemID.hdrLighting, !value);
        #endregion

        #region 驢땡
        public static bool IsVibration(this IGlobalOptions options) => options.GetOptionBool(LogicOptionItemID.vibration);
        public static void SetVibration(this IGlobalOptions options, bool value) => options.SetOptionBool(LogicOptionItemID.fullscreen, value);
        #endregion

        #region 沂宅鉅욥
